  1875	  private formatFixForInsertion(code: string, doc: vscode.TextDocument, line: number): string {
  1876	    const normalized = code.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  1877	    const rawLines = normalized.split("\n");
  1878	
  1879	    while (rawLines.length > 0 && rawLines[0].trim() === "") rawLines.shift();
  1880	    while (rawLines.length > 0 && rawLines[rawLines.length - 1].trim() === "") rawLines.pop();
  1881	
  1882	    if (rawLines.length === 0) return "";
  1883	
  1884	    const baseIndent = this.getLineIndent(doc, line);
  1885	    const minIndent = this.getMinIndent(rawLines);
  1886	
  1887	    const adjusted = rawLines
  1888	      .map((current) => {
  1889	        if (current.trim() === "") return "";
  1890	        const currentIndent = (current.match(/^\s*/) ?? [""])[0].length;
  1891	        const removeCount = Math.min(minIndent, currentIndent);
  1892	        return `${baseIndent}${current.slice(removeCount)}`;
  1893	      })
  1894	      .join("\n");
  1895	
  1896	    return adjusted.endsWith("\n") ? adjusted : `${adjusted}\n`;
  1897	  }
