  1899	  private getLineIndent(doc: vscode.TextDocument, line: number): string {
  1900	    if (line < 0 || line >= doc.lineCount) return "";
  1901	    const text = doc.lineAt(line).text;
  1902	    return (text.match(/^\s*/) ?? [""])[0];
  1903	  }
  1904	
  1905	  private getMinIndent(lines: string[]): number {
  1906	    const nonEmpty = lines.filter((line) => line.trim().length > 0);
  1907	    if (nonEmpty.length === 0) return 0;
  1908	    return nonEmpty.reduce((min, line) => {
  1909	      const indent = (line.match(/^\s*/) ?? [""])[0].length;
  1910	      return Math.min(min, indent);
  1911	    }, Number.MAX_SAFE_INTEGER);
  1912	  }
