  1914	  private isDuplicateFix(doc: vscode.TextDocument, textToInsert: string, line: number): boolean {
  1915	    const normalizedSnippet = textToInsert.trimEnd();
  1916	    if (!normalizedSnippet) return true;
  1917	
  1918	    const fullText = doc.getText();
  1919	    if (fullText.includes(normalizedSnippet)) {
  1920	      return true;
  1921	    }
  1922	
  1923	    const snippetLineCount = normalizedSnippet.split("\n").length;
  1924	    const endLine = Math.min(doc.lineCount - 1, line + snippetLineCount - 1);
  1925	    if (line <= endLine && doc.lineCount > 0) {
  1926	      const start = new vscode.Position(line, 0);
  1927	      const end = doc.lineAt(endLine).range.end;
  1928	      const existing = doc.getText(new vscode.Range(start, end)).trimEnd();
  1929	      if (existing === normalizedSnippet) {
  1930	        return true;
  1931	      }
  1932	    }
  1933	
  1934	    return false;
  1935	  }
