    46	function buildGraph(endpoints: EndpointRecord[], clusterBy = "provider"): GraphData {
    47	  const nodes: GraphNode[] = endpoints.map((ep) => ({
    48	    id: ep.id,
    49	    label: `${ep.method} ${ep.url}`,
    50	    provider: ep.provider,
    51	    monthlyCost: ep.monthlyCost,
    52	    callsPerDay: ep.callsPerDay,
    53	    status: ep.status,
    54	    group: clusterBy === "file" ? (ep.files[0] ?? ep.provider) : ep.provider,
    55	    frequencyClass: ep.frequencyClass,
    56	    costModel: ep.costModel,
    57	  }));
    58	
    59	  const fileToEndpoints = new Map<string, string[]>();
    60	  for (const ep of endpoints) {
    61	    for (const cs of ep.callSites) {
    62	      const list = fileToEndpoints.get(cs.file) ?? [];
    63	      list.push(ep.id);
    64	      fileToEndpoints.set(cs.file, list);
    65	    }
    66	  }
    67	
    68	  const seen = new Set<string>();
    69	  const edges: GraphEdge[] = [];
    70	  for (const epIds of fileToEndpoints.values()) {
    71	    const unique = [...new Set(epIds)];
    72	    for (let i = 0; i < unique.length - 1; i++) {
    73	      for (let j = i + 1; j < unique.length; j++) {
    74	        const key = `${unique[i]}<>${unique[j]}`;
    75	        if (!seen.has(key)) {
    76	          seen.add(key);
    77	          edges.push({ source: unique[i], target: unique[j], line: 0 });
    78	        }
    79	      }
    80	    }
    81	  }
    82	
    83	  // Cross-file edges: dashed edges from endpoints that propagated via cross-file resolution
    84	  for (const ep of endpoints) {
    85	    if (!ep.crossFileOrigins || ep.crossFileOrigins.length === 0) continue;
    86	    // Find other endpoints whose files include the cross-file origin file
    87	    for (const origin of ep.crossFileOrigins) {
    88	      const originFile = origin.file;
    89	      const originEpIds = fileToEndpoints.get(originFile) ?? [];
    90	      for (const originEpId of originEpIds) {
    91	        if (originEpId === ep.id) continue;
    92	        const key = `xf:${originEpId}>${ep.id}`;
    93	        if (!seen.has(key)) {
    94	          seen.add(key);
    95	          edges.push({ source: originEpId, target: ep.id, line: 0, crossFile: true });
    96	        }
    97	      }
    98	    }
    99	  }
