    11	export function Markdown({ content, addCopyButtons = false, className = "" }: MarkdownProps) {
    12	  const ref = useRef<HTMLDivElement>(null);
    13	
    14	  useEffect(() => {
    15	    if (!ref.current) return;
    16	
    17	    // Close any unclosed code fences (can happen with truncated LLM responses)
    18	    const fenceCount = (content.match(/```/g) ?? []).length;
    19	    const safeContent = fenceCount % 2 !== 0 ? content + "\n```" : content;
    20	
    21	    const html = marked.parse(safeContent) as string;
    22	    ref.current.innerHTML = DOMPurify.sanitize(html);
    23	
    24	    if (addCopyButtons) {
    25	      ref.current.querySelectorAll("pre").forEach((pre) => {
    26	        const code = pre.querySelector("code")?.textContent ?? pre.textContent ?? "";
    27	
    28	        const btn = document.createElement("button");
    29	        btn.className = "eco-code-copy codicon codicon-copy";
    30	        btn.title = "Copy";
    31	        btn.onclick = () => {
    32	          navigator.clipboard.writeText(code);
    33	          btn.className = "eco-code-copy codicon codicon-check";
    34	          setTimeout(() => {
    35	            btn.className = "eco-code-copy codicon codicon-copy";
    36	          }, 2000);
    37	        };
    38	
    39	        pre.appendChild(btn);
    40	      });
    41	    }
    42	  }, [content, addCopyButtons]);
    43	
    44	  return <div ref={ref} className={`eco-md ${className}`} />;
